from datetime import datetime

def fn_collect_metrics():
    """
    模拟收集每日指标数据。
    返回: dict with 'data' list and 'count'
    """
    # 模拟随机有数据/无数据的情况
    has_data = random.random() > 0.3  # 70% 概率有数据
    if has_data:
        data = [
            {"metric": "active_users", "value": random.randint(100, 500)},
            {"metric": "new_signups", "value": random.randint(10, 50)},
            {"metric": "revenue", "value": round(random.uniform(1000, 10000), 2)},
            {"metric": "errors", "value": random.randint(0, 10)},
        ]
        return {"data": data, "count": len(data), "collected_at": datetime.utcnow().isoformat()}
    else:
        return {"data": [], "count": 0, "collected_at": datetime.utcnow().isoformat()}
